import React, { useState } from 'react';
import toast from 'react-hot-toast';
import { addBulkVideos, uploadExcel, importGoogleSheet } from '../services/api';

export default function BulkUpload() {
  const [urlText, setUrlText] = useState('');
  const [file, setFile] = useState(null);
  const [sheetUrl, setSheetUrl] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handlePasteSubmit = async () => {
    const lines = urlText
      .split('\n')
      .map((l) => l.trim())
      .filter(Boolean);
    if (lines.length === 0) return toast.error('Paste at least one URL');

    setLoading(true);
    try {
      const res = await addBulkVideos(lines);
      setResult(res.data);
      toast.success(`Added ${res.data.added} videos`);
      setUrlText('');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed');
    } finally {
      setLoading(false);
    }
  };

  const handleFileSubmit = async () => {
    if (!file) return toast.error('Select a file first');
    setLoading(true);
    try {
      const res = await uploadExcel(file);
      setResult(res.data);
      toast.success(`Added ${res.data.added} videos`);
      setFile(null);
    } catch (err) {
      toast.error(err.response?.data?.error || 'Upload failed');
    } finally {
      setLoading(false);
    }
  };

  const handleSheetSubmit = async () => {
    if (!sheetUrl.trim()) return toast.error('Enter a Google Sheet URL');
    setLoading(true);
    try {
      const res = await importGoogleSheet(sheetUrl.trim());
      setResult(res.data);
      toast.success(`Imported ${res.data.added} videos from Google Sheet`);
      setSheetUrl('');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Import failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="upload-section">
      <h1>Add Videos to Track</h1>

      {result && (
        <div className="results-banner success">
          Added: {result.added} &nbsp;|&nbsp; Duplicates: {result.duplicates}
          {result.errors?.length > 0 && (
            <span> &nbsp;|&nbsp; Errors: {result.errors.length}</span>
          )}
        </div>
      )}

      {/* ── Paste URLs ─────────────────── */}
      <div className="upload-card">
        <h3>Paste URLs (one per line)</h3>
        <textarea
          placeholder={
            'https://www.instagram.com/reel/...\nhttps://www.tiktok.com/@user/video/...'
          }
          value={urlText}
          onChange={(e) => setUrlText(e.target.value)}
        />
        <button
          className="btn btn-primary mt-12"
          disabled={loading}
          onClick={handlePasteSubmit}
        >
          {loading ? 'Submitting…' : 'Submit URLs'}
        </button>
      </div>

      {/* ── Upload Excel ───────────────── */}
      <div className="upload-card">
        <h3>Upload Excel File (.xlsx)</h3>
        <p style={{ fontSize: '0.85rem', color: '#888', marginBottom: 12 }}>
          Columns: URL, Creator, Campaign, Platform
        </p>
        <input
          type="file"
          accept=".xlsx,.xls,.csv"
          onChange={(e) => setFile(e.target.files[0])}
        />
        <button
          className="btn btn-primary mt-12"
          disabled={loading || !file}
          onClick={handleFileSubmit}
        >
          {loading ? 'Uploading…' : 'Upload & Import'}
        </button>
      </div>

      {/* ── Google Sheet ───────────────── */}
      <div className="upload-card">
        <h3>Import from Google Sheet</h3>
        <p style={{ fontSize: '0.85rem', color: '#888', marginBottom: 12 }}>
          Make sure the sheet is publicly accessible (Anyone with the link can view).
          Columns: URL, Creator, Campaign, Platform
        </p>
        <input
          type="text"
          placeholder="https://docs.google.com/spreadsheets/d/..."
          value={sheetUrl}
          onChange={(e) => setSheetUrl(e.target.value)}
        />
        <button
          className="btn btn-primary mt-12"
          disabled={loading || !sheetUrl.trim()}
          onClick={handleSheetSubmit}
        >
          {loading ? 'Importing…' : 'Import from Sheet'}
        </button>
      </div>
    </div>
  );
}
